import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundColonAnnotationTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given an annotation with spacing around colon`() {
        val code =
            """
            @file :JvmName("Foo")
            @file: JvmName("Foo")
            @file : JvmName("Foo")

            @set :[Inject VisibleForTesting]
            @set: [Inject VisibleForTesting]
            @set : [Inject VisibleForTesting]
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            @file:JvmName("Foo")
            @file:JvmName("Foo")

            @set:[Inject VisibleForTesting]
            @set:[Inject VisibleForTesting]
            @set:[Inject VisibleForTesting]
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 6, "Unexpected spacing around \":\""),
                LintViolation(2, 6, "Unexpected spacing around \":\""),
                LintViolation(3, 6, "Unexpected spacing around \":\""),
                LintViolation(5, 5, "Unexpected spacing around \":\""),
                LintViolation(6, 5, "Unexpected spacing around \":\""),
                LintViolation(7, 5, "Unexpected spacing around \":\"")
            )
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an annotation without spacing around colon`() {
        val code =
            """
            @file:JvmName("Foo")
            @set:[Inject VisibleForTesting]
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
    }
}
